"use client";

import { createContext, useContext } from "react";
import type { CursorId, SwirskiCursor } from "./cursors";

export type CursorContextValue = {
  cursor: SwirskiCursor;
  cursorId: CursorId;
  cursors: SwirskiCursor[];
  setCursor: (cursorId: CursorId) => void;
};

export const CursorContext = createContext<CursorContextValue | null>(null);

export function useSwirskiCursor() {
  const context = useContext(CursorContext);

  if (!context) {
    throw new Error("useSwirskiCursor must be used inside CursorProvider.");
  }

  return context;
}

"use client";

import { HTMLAttributes, forwardRef, useState } from "react";
import { cn, swirskiAttrs } from "../../system";
import { CursorPicker } from "./CursorPicker";
import { useSwirskiCursor } from "./CursorProvider";

export type CursorDockProps = {
  label?: string;
  position?: "fixed" | "absolute";
  side?: "left" | "right";
  variant?: "default";
  size?: "md";
  tone?: "default";
} & HTMLAttributes<HTMLDivElement>;

export const CursorDock = forwardRef<HTMLDivElement, CursorDockProps>(
  function CursorDock({
  className,
  label = "Choose cursor",
  position = "fixed",
  side = "right",
  variant = "default",
  size = "md",
  tone = "default",
  onBlur,
  onFocus,
  onMouseEnter,
  onMouseLeave,
  ...props
}, ref) {
  const { cursor } = useSwirskiCursor();
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div
      ref={ref}
      className={cn(
        "group top-1/2 z-50 hidden -translate-y-1/2 items-center gap-0 lg:flex",
        position === "fixed" ? "fixed" : "absolute",
        side === "right" ? "right-0 flex-row" : "left-0 flex-row-reverse",
        className,
      )}
      onBlur={(event) => {
        onBlur?.(event);

        if (!event.currentTarget.contains(event.relatedTarget)) {
          setIsOpen(false);
        }
      }}
      onFocus={(event) => {
        onFocus?.(event);
        setIsOpen(true);
      }}
      onMouseEnter={(event) => {
        onMouseEnter?.(event);
        setIsOpen(true);
      }}
      onMouseLeave={(event) => {
        onMouseLeave?.(event);
        setIsOpen(false);
      }}
      {...swirskiAttrs("cursor-dock", { size, tone, variant })}
      {...props}
    >
      <div
        aria-hidden={!isOpen}
        className={cn(
          "overflow-hidden transition-[max-width,opacity,transform] duration-200 ease-out",
          isOpen
            ? "max-w-[calc(100vw-5rem)] opacity-100"
            : "max-w-0 opacity-0",
          side === "right"
            ? isOpen
              ? "translate-x-0"
              : "translate-x-4"
            : isOpen
              ? "translate-x-0"
              : "-translate-x-4",
        )}
      >
        <CursorPicker
          className={cn(
            "mx-3 w-max max-w-[calc(100vw-6rem)]",
            !isOpen && "pointer-events-none",
          )}
          label={label}
          buttonTabIndex={isOpen ? undefined : -1}
          showLabels
        />
      </div>

      <button
        aria-expanded={isOpen}
        aria-label={label}
        className={cn(
          "grid size-14 place-items-center border-4 border-black bg-[#FFD400] shadow-[5px_5px_0_#0B0B0C] transition-all duration-150",
          "hover:translate-x-1 hover:translate-y-1 hover:shadow-none",
          "focus-visible:outline focus-visible:outline-4 focus-visible:outline-offset-2 focus-visible:outline-[#0057FF]",
          side === "right" ? "border-r-0" : "border-l-0",
        )}
        onClick={() => setIsOpen((open) => !open)}
        type="button"
        {...swirskiAttrs("cursor-dock-trigger", { size, tone, variant })}
      >
        <span
          aria-hidden="true"
          className="block size-8 bg-contain bg-center bg-no-repeat"
          style={{ backgroundImage: `url("${cursor.preview}")` }}
        />
      </button>
    </div>
  );
});

CursorDock.displayName = "CursorDock";

"use client";

import { HTMLAttributes, forwardRef } from "react";
import { cn, swirskiAttrs } from "../../system";
import { useSwirskiCursor } from "./CursorProvider";

export type CursorPickerProps = {
  buttonTabIndex?: number;
  label?: string;
  showLabels?: boolean;
  variant?: "default";
  size?: "md";
  tone?: "default";
} & HTMLAttributes<HTMLDivElement>;

export const CursorPicker = forwardRef<HTMLDivElement, CursorPickerProps>(
  function CursorPicker({
  buttonTabIndex,
  className,
  label = "Cursor",
  showLabels = true,
  variant = "default",
  size = "md",
  tone = "default",
  ...props
}, ref) {
  const { cursorId, cursors, setCursor } = useSwirskiCursor();

  return (
    <div
      ref={ref}
      aria-label={label}
      className={cn(
        "inline-flex flex-wrap gap-2 border-4 border-black bg-[#F5F5F3] p-2 shadow-[6px_6px_0_#0B0B0C]",
        className,
      )}
      role="radiogroup"
      {...swirskiAttrs("cursor-picker", { size, tone, variant })}
      {...props}
    >
      {cursors.map((cursor) => {
        const isSelected = cursor.id === cursorId;

        return (
          <button
            aria-checked={isSelected}
            aria-label={cursor.name}
            className={cn(
              "group relative flex min-h-14 min-w-14 items-center gap-2 border-4 border-black bg-white px-3 py-2 text-left transition-all duration-150",
              "hover:-translate-y-1 hover:shadow-[5px_5px_0_#0B0B0C]",
              "focus-visible:outline focus-visible:outline-4 focus-visible:outline-offset-2 focus-visible:outline-[#0057FF]",
              isSelected
                ? "translate-x-1 translate-y-1 shadow-none"
                : "shadow-[4px_4px_0_#0B0B0C]",
            )}
            key={cursor.id}
            onClick={() => setCursor(cursor.id)}
            role="radio"
            style={{ backgroundColor: isSelected ? cursor.swatch : undefined }}
            tabIndex={buttonTabIndex}
            title={cursor.description}
            type="button"
          >
            <span
              aria-hidden="true"
              className="block size-8 shrink-0 bg-contain bg-center bg-no-repeat"
              style={{ backgroundImage: `url("${cursor.preview}")` }}
            />

            {showLabels ? (
              <span
                className={cn(
                  "pr-1 font-black uppercase leading-none tracking-normal",
                  isSelected && cursor.id !== "bolt"
                    ? "text-white"
                    : "text-black",
                )}
              >
                {cursor.name}
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
});

CursorPicker.displayName = "CursorPicker";

import { fireEvent, render, screen } from "@testing-library/react";
import { describe, expect, it } from "vitest";
import { CursorProvider } from "./CursorProvider";

describe("CursorProvider", () => {
  it("publishes custom cursor variables for the supported interaction states", () => {
    render(
      <CursorProvider data-testid="provider" storageKey={false}>
        <button type="button">Hover me</button>
      </CursorProvider>,
    );

    const provider = screen.getByTestId("provider");

    expect(document.body).toHaveAttribute("data-swirski-cursor", "bolt");
    expect(provider.style.getPropertyValue("--swirski-cursor-grab")).toContain(
      "grab",
    );
    expect(
      provider.style.getPropertyValue("--swirski-cursor-grabbing"),
    ).toContain("grabbing");
    expect(
      provider.style.getPropertyValue("--swirski-cursor-disabled"),
    ).toContain("not-allowed");
    expect(
      provider.style.getPropertyValue("--swirski-cursor-not-allowed"),
    ).toContain("not-allowed");
    expect(
      provider.style.getPropertyValue("--swirski-cursor-progress"),
    ).toContain("progress");
  });

  it("switches pressed state for panning targets without overriding text input", () => {
    render(
      <CursorProvider data-testid="provider" storageKey={false}>
        <button type="button">Press me</button>
        <div data-cursor="pan" data-testid="pan-surface">
          <button type="button">Nested action</button>
        </div>
        <div data-cursor="disabled" data-testid="disabled-surface">
          Locked
        </div>
        <input aria-label="Title" />
      </CursorProvider>,
    );

    const provider = screen.getByTestId("provider");

    fireEvent.pointerDown(screen.getByTestId("pan-surface"), {
      pointerType: "mouse",
    });
    expect(provider).toHaveAttribute(
      "data-swirski-cursor-pressed-state",
      "grabbing",
    );

    fireEvent.pointerUp(window);
    expect(provider).not.toHaveAttribute("data-swirski-cursor-pressed-state");

    fireEvent.pointerDown(screen.getByRole("button", { name: "Press me" }), {
      pointerType: "mouse",
    });
    expect(provider).toHaveAttribute(
      "data-swirski-cursor-pressed-state",
      "active",
    );

    fireEvent.pointerUp(window);
    fireEvent.pointerDown(
      screen.getByRole("button", { name: "Nested action" }),
      {
        pointerType: "mouse",
      },
    );
    expect(provider).toHaveAttribute(
      "data-swirski-cursor-pressed-state",
      "active",
    );

    fireEvent.pointerUp(window);
    fireEvent.pointerDown(screen.getByRole("textbox", { name: "Title" }), {
      pointerType: "mouse",
    });
    expect(provider).not.toHaveAttribute("data-swirski-cursor-pressed-state");

    fireEvent.pointerDown(screen.getByTestId("disabled-surface"), {
      pointerType: "mouse",
    });
    expect(provider).not.toHaveAttribute("data-swirski-cursor-pressed-state");
  });
});

"use client";

import type { HTMLAttributes, ReactNode } from "react";
import {
  forwardRef,
  useCallback,
  useEffect,
  useMemo,
  useState,
} from "react";
import { cn, swirskiAttrs } from "../../system";
import { CursorContext } from "./CursorContext";
import {
  cursorSelectorStyles,
  cursorVariableNames,
} from "./cursor-selectors";
import {
  getPressedCursorState,
  type PressedCursorState,
} from "./cursor-state";
import { getCursorStyle } from "./cursor-style";
import { findCursor, getStoredCursor, storeCursor } from "./cursor-storage";
import {
  swirskiCursors,
  type CursorId,
  type SwirskiCursor,
} from "./cursors";

export { useSwirskiCursor } from "./CursorContext";

export type CursorProviderProps = {
  children: ReactNode;
  cursors?: SwirskiCursor[];
  cursor?: CursorId;
  defaultCursor?: CursorId;
  onCursorChange?: (cursorId: CursorId) => void;
  storageKey?: string | false;
  variant?: "default";
  size?: "md";
  tone?: "default";
} & HTMLAttributes<HTMLDivElement>;

export const CursorProvider = forwardRef<HTMLDivElement, CursorProviderProps>(
  function CursorProvider(
    {
      children,
      className,
      cursors = swirskiCursors,
      cursor,
      defaultCursor = "bolt",
      onCursorChange,
      storageKey = "swirski-cursor",
      variant = "default",
      size = "md",
      tone = "default",
      onPointerDownCapture,
      style,
      ...props
    },
    ref,
  ) {
    const isControlled = cursor !== undefined;

    const [selectedCursor, setSelectedCursor] = useState<CursorId>(() => {
      return defaultCursor;
    });

    const [pressedCursor, setPressedCursor] =
      useState<PressedCursorState | null>(null);

    useEffect(() => {
      if (isControlled) {
        return;
      }

      const storedCursor = getStoredCursor(storageKey, cursors);

      if (storedCursor) {
        setSelectedCursor(storedCursor);
      }
    }, [cursors, isControlled, storageKey]);

    useEffect(() => {
      if (!pressedCursor || typeof window === "undefined") {
        return;
      }

      const releaseCursor = () => {
        setPressedCursor(null);
      };

      window.addEventListener("pointerup", releaseCursor);
      window.addEventListener("pointercancel", releaseCursor);
      window.addEventListener("blur", releaseCursor);
      window.addEventListener("contextmenu", releaseCursor);

      return () => {
        window.removeEventListener("pointerup", releaseCursor);
        window.removeEventListener("pointercancel", releaseCursor);
        window.removeEventListener("blur", releaseCursor);
        window.removeEventListener("contextmenu", releaseCursor);
      };
    }, [pressedCursor]);

    const cursorId = cursor ?? selectedCursor;

    const activeCursor = useMemo(() => {
      return findCursor(cursors, cursorId);
    }, [cursors, cursorId]);

    const setCursor = useCallback(
      (nextCursor: CursorId) => {
        const cursorExists = cursors.some((cursor) => cursor.id === nextCursor);

        if (!cursorExists) {
          return;
        }

        if (!isControlled) {
          setSelectedCursor(nextCursor);
        }

        storeCursor(storageKey, nextCursor);
        onCursorChange?.(nextCursor);
      },
      [cursors, isControlled, onCursorChange, storageKey],
    );

    const value = useMemo(
      () => ({
        cursor: activeCursor,
        cursorId: activeCursor.id,
        cursors,
        setCursor,
      }),
      [activeCursor, cursors, setCursor],
    );

    const cursorStyle = useMemo(() => {
      return getCursorStyle(activeCursor);
    }, [activeCursor]);

    useEffect(() => {
      if (typeof document === "undefined") {
        return;
      }

      const body = document.body;
      const previousCursor = body.getAttribute("data-swirski-cursor");
      const previousVariables = cursorVariableNames.map((name) =>
        body.style.getPropertyValue(name),
      );

      body.setAttribute("data-swirski-cursor", activeCursor.id);
      cursorVariableNames.forEach((name) => {
        const value = cursorStyle[name];

        if (typeof value === "string") {
          body.style.setProperty(name, value);
        }
      });

      return () => {
        if (previousCursor === null) {
          body.removeAttribute("data-swirski-cursor");
        } else {
          body.setAttribute("data-swirski-cursor", previousCursor);
        }

        cursorVariableNames.forEach((name, index) => {
          const previousValue = previousVariables[index];

          if (previousValue) {
            body.style.setProperty(name, previousValue);
          } else {
            body.style.removeProperty(name);
          }
        });
      };
    }, [activeCursor.id, cursorStyle]);

    return (
      <CursorContext.Provider value={value}>
        <style>{cursorSelectorStyles}</style>

        <div
          ref={ref}
          className={cn("min-h-full", className)}
          data-swirski-cursor={activeCursor.id}
          data-swirski-cursor-pressed={pressedCursor ? "true" : undefined}
          data-swirski-cursor-pressed-state={pressedCursor ?? undefined}
          {...swirskiAttrs("cursor-provider", { size, tone, variant })}
          style={{ ...cursorStyle, ...style }}
          onPointerDownCapture={(event) => {
            onPointerDownCapture?.(event);

            if (event.pointerType === "mouse") {
              setPressedCursor(getPressedCursorState(event.target));
            }
          }}
          {...props}
        >
          {children}
        </div>
      </CursorContext.Provider>
    );
  },
);

CursorProvider.displayName = "CursorProvider";

export const cursorVariableNames = [
  "--swirski-cursor",
  "--swirski-cursor-active",
  "--swirski-cursor-copy",
  "--swirski-cursor-crosshair",
  "--swirski-cursor-disabled",
  "--swirski-cursor-grab",
  "--swirski-cursor-grabbing",
  "--swirski-cursor-help",
  "--swirski-cursor-move",
  "--swirski-cursor-not-allowed",
  "--swirski-cursor-pointer",
  "--swirski-cursor-progress",
  "--swirski-cursor-resize",
  "--swirski-cursor-text",
  "--swirski-cursor-wait",
  "--swirski-cursor-zoom-in",
  "--swirski-cursor-zoom-out",
] as const;

export const cursorSelectorStyles = `
@media (min-width: 1024px) and (hover: hover) and (pointer: fine) {
  [data-swirski-cursor] {
    cursor: var(--swirski-cursor);
  }

  [data-swirski-cursor] :is(
    a,
    button,
    summary,
    label,
    select,
    input[type="range"],
    input[type="button"],
    input[type="checkbox"],
    input[type="radio"],
    input[type="reset"],
    input[type="submit"],
    [role="button"],
    .cursor-pointer,
    [data-cursor="pointer"]
  ) {
    cursor: var(--swirski-cursor-pointer);
  }

  [data-swirski-cursor] :is(
    input:not([type="button"]):not([type="checkbox"]):not([type="radio"]):not([type="range"]):not([type="reset"]):not([type="submit"]),
    textarea,
    [contenteditable="true"],
    .cursor-text,
    [data-cursor="text"]
  ) {
    cursor: var(--swirski-cursor-text);
  }

  [data-swirski-cursor] :is(
    [data-cursor="zoom-in"],
    [data-swirski-cursor-zoom="in"],
    .cursor-zoom-in
  ) {
    cursor: var(--swirski-cursor-zoom-in);
  }

  [data-swirski-cursor] :is(
    [data-cursor="zoom-out"],
    [data-swirski-cursor-zoom="out"],
    .cursor-zoom-out
  ) {
    cursor: var(--swirski-cursor-zoom-out);
  }

  [data-swirski-cursor] :is(
    [data-cursor="grab"],
    [data-cursor="pan"],
    [data-swirski-cursor-pan="true"],
    [draggable="true"],
    .cursor-grab
  ) {
    cursor: var(--swirski-cursor-grab);
  }

  [data-swirski-cursor] :is(
    [data-cursor="grabbing"],
    [data-cursor="panning"],
    [data-swirski-cursor-panning="true"],
    .cursor-grabbing
  ),
  [data-swirski-cursor] :is(
    [data-cursor="grab"],
    [data-cursor="pan"],
    [data-swirski-cursor-pan="true"],
    [draggable="true"],
    .cursor-grab
  ):active {
    cursor: var(--swirski-cursor-grabbing);
  }

  [data-swirski-cursor] :is(
    [data-cursor="move"],
    .cursor-all-scroll,
    .cursor-move
  ) {
    cursor: var(--swirski-cursor-move);
  }

  [data-swirski-cursor] :is(
    [data-cursor="resize"],
    [data-cursor$="-resize"],
    [data-resize-handle],
    [data-swirski-cursor-resize="true"],
    .cursor-col-resize,
    .cursor-ew-resize,
    .cursor-nesw-resize,
    .cursor-ns-resize,
    .cursor-nwse-resize,
    .cursor-row-resize
  ) {
    cursor: var(--swirski-cursor-resize);
  }

  [data-swirski-cursor] :is(
    [data-cursor="copy"],
    [data-cursor="alias"],
    .cursor-alias,
    .cursor-copy
  ) {
    cursor: var(--swirski-cursor-copy);
  }

  [data-swirski-cursor] :is(
    [data-cursor="crosshair"],
    [data-cursor="cell"],
    .cursor-cell,
    .cursor-crosshair
  ) {
    cursor: var(--swirski-cursor-crosshair);
  }

  [data-swirski-cursor] :is(
    [data-cursor="help"],
    .cursor-help
  ) {
    cursor: var(--swirski-cursor-help);
  }

  [data-swirski-cursor] :is(
    [aria-busy="true"],
    [data-busy="true"],
    [data-cursor="progress"],
    [data-loading="true"],
    .cursor-progress
  ) {
    cursor: var(--swirski-cursor-progress);
  }

  [data-swirski-cursor] :is(
    [data-cursor="wait"],
    .cursor-wait
  ) {
    cursor: var(--swirski-cursor-wait);
  }

  [data-swirski-cursor] :is(
    [data-cursor="not-allowed"],
    .cursor-not-allowed
  ) {
    cursor: var(--swirski-cursor-not-allowed);
  }

  [data-swirski-cursor] :is(
    [data-cursor="active"],
    [data-swirski-cursor-state="active"],
    .cursor-active
  ) {
    cursor: var(--swirski-cursor-active);
  }

  [data-swirski-cursor] :is(
    a,
    button,
    summary,
    label,
    select,
    input[type="range"],
    input[type="button"],
    input[type="checkbox"],
    input[type="radio"],
    input[type="reset"],
    input[type="submit"],
    [role="button"],
    .cursor-pointer,
    [data-cursor="pointer"],
    [data-cursor="active"]
  ):active {
    cursor: var(--swirski-cursor-active);
  }

  [data-swirski-cursor][data-swirski-cursor-pressed-state="active"],
  [data-swirski-cursor][data-swirski-cursor-pressed-state="active"] * {
    cursor: var(--swirski-cursor-active);
  }

  [data-swirski-cursor][data-swirski-cursor-pressed-state="grabbing"],
  [data-swirski-cursor][data-swirski-cursor-pressed-state="grabbing"] * {
    cursor: var(--swirski-cursor-grabbing);
  }

  [data-swirski-cursor][data-swirski-cursor] :is(
    :disabled,
    [aria-disabled="true"],
    [data-cursor="disabled"],
    [data-disabled="true"],
    [data-state="disabled"],
    [disabled],
    .cursor-disabled
  ),
  [data-swirski-cursor][data-swirski-cursor] :is(
    :disabled,
    [aria-disabled="true"],
    [data-cursor="disabled"],
    [data-disabled="true"],
    [data-state="disabled"],
    [disabled],
    .cursor-disabled
  ):is(:hover, :active),
  [data-swirski-cursor][data-swirski-cursor] :is(
    :disabled,
    [aria-disabled="true"],
    [data-cursor="disabled"],
    [data-disabled="true"],
    [data-state="disabled"],
    [disabled],
    .cursor-disabled
  ) * {
    cursor: var(--swirski-cursor-disabled);
  }
}
`;

export type PressedCursorState = "active" | "grabbing";

const disabledCursorSelector = [
  ":disabled",
  "[aria-disabled=\"true\"]",
  "[data-cursor=\"disabled\"]",
  "[data-cursor=\"not-allowed\"]",
  "[data-disabled=\"true\"]",
  "[data-state=\"disabled\"]",
  "[disabled]",
  ".cursor-disabled",
  ".cursor-not-allowed",
].join(", ");

const panningCursorSelector = [
  "[data-cursor=\"grab\"]",
  "[data-cursor=\"grabbing\"]",
  "[data-cursor=\"pan\"]",
  "[data-cursor=\"panning\"]",
  "[data-swirski-cursor-pan=\"true\"]",
  "[data-swirski-cursor-panning=\"true\"]",
  "[draggable=\"true\"]",
  ".cursor-grab",
  ".cursor-grabbing",
].join(", ");

const activeCursorSelector = [
  "a",
  "button",
  "summary",
  "label",
  "select",
  "input[type=\"range\"]",
  "input[type=\"button\"]",
  "input[type=\"checkbox\"]",
  "input[type=\"radio\"]",
  "input[type=\"reset\"]",
  "input[type=\"submit\"]",
  "[role=\"button\"]",
  ".cursor-pointer",
  "[data-cursor=\"active\"]",
  "[data-cursor=\"pointer\"]",
].join(", ");

export function getPressedCursorState(target: EventTarget | null) {
  if (typeof Element === "undefined" || !(target instanceof Element)) {
    return null;
  }

  if (target.closest(disabledCursorSelector)) {
    return null;
  }

  const panningElement = target.closest(panningCursorSelector);
  const activeElement = target.closest(activeCursorSelector);

  if (
    panningElement &&
    (!activeElement ||
      panningElement === activeElement ||
      activeElement.contains(panningElement))
  ) {
    return "grabbing";
  }

  if (activeElement) {
    return "active";
  }

  return null;
}

import {
  getSwirskiCursor,
  swirskiCursors,
  type CursorId,
  type SwirskiCursor,
} from "./cursors";

export function getStoredCursor(
  storageKey: string | false,
  cursors: SwirskiCursor[],
): CursorId | null {
  if (storageKey === false || typeof window === "undefined") {
    return null;
  }

  try {
    const storedCursor = window.localStorage.getItem(storageKey);

    if (!storedCursor) {
      return null;
    }

    const exists = cursors.some((cursor) => cursor.id === storedCursor);

    return exists ? (storedCursor as CursorId) : null;
  } catch {
    return null;
  }
}

export function storeCursor(storageKey: string | false, cursorId: CursorId) {
  if (storageKey === false || typeof window === "undefined") {
    return;
  }

  try {
    window.localStorage.setItem(storageKey, cursorId);
  } catch {
    // Ignore storage errors, for example private browsing or blocked storage.
  }
}

export function findCursor(cursors: SwirskiCursor[], cursorId: CursorId) {
  return (
    cursors.find((cursor) => cursor.id === cursorId) ??
    getSwirskiCursor(cursorId) ??
    cursors[0] ??
